var doc = Rhino.RhinoDoc.ActiveDoc;
var awareLayerIndex = doc.Layers.FindName("AWARE")?.Index ?? -1;
if (awareLayerIndex < 0) return new { ok = false, error = "layer 'AWARE' does not exist; create it first (prompt 10)" };
int moved = 0;
foreach (var obj in doc.Objects.GetSelectedObjects(false, false))
{
    var attrs = obj.Attributes.Duplicate();
    attrs.LayerIndex = awareLayerIndex;
    if (doc.Objects.ModifyAttributes(obj, attrs, false)) moved++;
}
doc.Views.Redraw();
return new { ok = true, moved = moved, target_layer = "AWARE" };
